const rankedLogos = rankedLogoIds.map((id) => logos.find((logo) => logo.id === id)).filter((logo): logo is LogoSpec => Boolean(logo));

function dataUri(svg: string) { return `data:image/svg+xml;charset=utf-8,${encodeURIComponent(svg)}`; }

export default function LogoLabPage() {
  return <div className="min-h-screen bg-surface-base px-4 py-10 text-foreground-primary sm:px-6 lg:px-spacing-10"><section className="mx-auto max-w-7xl"><div className="rounded-radius-3xl border border-foreground-primary/10 bg-surface-warm-white p-spacing-9 lovable-shadow-subtle sm:p-spacing-10"><p className="text-sm font-medium uppercase tracking-[0.24em] text-text-secondary">Logo Lab v2</p><h1 className="mt-3 max-w-4xl text-balance text-4xl font-semibold tracking-[-0.055em] sm:text-6xl">100 kandidat SVG logo premium, sudah diranking</h1><p className="mt-5 max-w-2xl text-base leading-7 text-text-secondary sm:text-lg">Dibuat ulang dengan prinsip logo timeless: simple, distinctive, scalable, appropriate, optically balanced, dan kuat di favicon kecil.</p></div><div className="mt-8 grid gap-spacing-7 sm:grid-cols-2 lg:grid-cols-4 xl:grid-cols-5">{rankedLogos.map((logo, index) => <article key={logo.id} className="rounded-radius-3xl border border-foreground-primary/10 bg-surface-warm-white p-4 lovable-shadow-subtle"><div className="flex aspect-square items-center justify-center rounded-radius-2xl bg-surface-base p-spacing-9">{/* eslint-disable-next-line @next/next/no-img-element */}
<img src={dataUri(logo.svg)} alt={logo.name} className="h-full w-full" /></div><div className="mt-4 flex items-start justify-between gap-3"><div><h2 className="text-sm font-medium">{logo.name}</h2><p className="mt-1 font-mono text-xs text-text-secondary">Rank #{String(index + 1).padStart(3, "0")} - ID {String(logo.id).padStart(3, "0")}</p><p className="mt-2 max-w-44 text-xs leading-5 text-text-secondary">{logo.reason}</p></div><a href={dataUri(logo.svg)} download={`umkmcepat-logo-${String(logo.id).padStart(3, "0")}.svg`} className="rounded-full border border-foreground-primary/10 px-3 py-1.5 text-xs font-medium transition hover:bg-foreground-primary hover:text-surface-warm-white">Download</a></div></article>)}</div></section></div>;
}
